'use strict';

import VectaraDocFactory from './vectaraDocFactory.js';
import SearcherFactory from './searcherFactory.js';
import { transportSvc } from '../services/transportSvc.js';
import { activeQueries } from '../values/activeQueries.js';
import { vectaraSearcherPreprocessorSvc } from '../services/vectaraSearcherPreprocessorSvc.js';
import { vectaraUrlSvc } from '../services/vectaraUrlSvc.js';

const Searcher = function (options) {
  SearcherFactory.call(this, options, vectaraSearcherPreprocessorSvc);
};

Searcher.prototype = Object.create(SearcherFactory.prototype);
Searcher.prototype.constructor = Searcher;

Searcher.prototype.pager = pager;
Searcher.prototype.search = search;

// return a new searcher that will give you
// the next page upon search(). To get the subsequent
// page, call pager on that searcher
function pager() {
  const self = this;
  let pagerArgs = {};
  const nextArgs = structuredClone(self.args);

  if (nextArgs.hasOwnProperty('pager') && nextArgs.pager !== undefined) {
    pagerArgs = nextArgs.pager;
  } else if (self.hasOwnProperty('pagerArgs') && self.pagerArgs !== undefined) {
    pagerArgs = self.pagerArgs;
  }

  if (pagerArgs.hasOwnProperty('from')) {
    pagerArgs.from = parseInt(pagerArgs.from) + pagerArgs.size;

    if (pagerArgs.from >= self.numFound) {
      return null; // no more results
    }
  } else {
    pagerArgs.from = pagerArgs.size;
  }

  nextArgs.pager = pagerArgs;
  const options = {
    args: nextArgs,
    config: self.config,
    fieldList: self.fieldList,
    queryText: self.queryText,
    type: self.type,
    url: self.url,
  };

  return new Searcher(options);
}

// search (execute the query) and produce results
// to the returned future
function search() {
  const self = this;
  const apiMethod = 'POST';
  const proxyUrl = self.config.proxyUrl;
  const url = self.url;
  const transport = transportSvc.getTransport({ apiMethod: apiMethod, proxyUrl: proxyUrl });

  const queryDslWithPagerArgs = structuredClone(self.queryDsl);
  if (self.pagerArgs) {
    queryDslWithPagerArgs.from = self.pagerArgs.from;
    queryDslWithPagerArgs.size = self.pagerArgs.size;
  }

  self.inError = false;

  const headers = vectaraUrlSvc.getHeaders(self.config.customHeaders);

  activeQueries.increment();
  return transport
    .query(url, queryDslWithPagerArgs, headers)
    .then(
      function success(httpConfig) {
        const data = httpConfig.data;
        activeQueries.decrement();

        const documents =
          data.responseSet && data.responseSet.length > 0 ? data.responseSet[0].document : [];

        self.numFound = documents.length;

        const parseDoc = function (doc, groupedBy, group) {
          const options = {
            groupedBy: groupedBy,
            group: group,
            fieldList: self.fieldList,
            url: self.url,
          };

          return new VectaraDocFactory(doc, options);
        };

        documents.forEach(function (docFromApi) {
          const doc = parseDoc(docFromApi);
          self.docs.push(doc);
        });
      },
      function error(msg) {
        activeQueries.decrement();
        self.inError = true;
        msg.searchError = 'Error with Vectara query or server. Review request manually.';
        return Promise.reject(msg);
      }
    )
    .catch(function (response) {
      console.debug('Failed to execute search');
      return Promise.reject(response);
    });
} // end of search()

export default Searcher;
