'use strict';

import HttpTransportFactory from '../factories/httpTransportFactory.js';
import HttpJsonpTransportFactory from '../factories/httpJsonpTransportFactory.js';
import BulkTransportFactory from '../factories/bulkTransportFactory.js';

const bulkTransport = new BulkTransportFactory({});
const httpPostTransport = new HttpTransportFactory({ method: 'POST' });
const httpGetTransport = new HttpTransportFactory({ method: 'GET' });
const httpJsonpTransport = new HttpJsonpTransportFactory({});

function getTransport(options) {
  let apiMethod = options.apiMethod;
  if (apiMethod !== undefined) {
    apiMethod = apiMethod.toUpperCase();
  }
  let transport = null;
  if (apiMethod === 'BULK') {
    transport = bulkTransport;
  } else if (apiMethod === 'JSONP') {
    transport = httpJsonpTransport;
  } else if (apiMethod === 'GET') {
    transport = httpGetTransport;
  } else {
    transport = httpPostTransport;
  }

  const proxyUrl = options.proxyUrl;
  if (proxyUrl !== undefined) {
    if (transport instanceof HttpJsonpTransportFactory) {
      throw new Error('It does not make sense to proxy a JSONP connection, use GET instead.');
    }
    // For BULK, wrap with a simple proxy that prepends the URL and delegates.
    // For GET/POST, create a new HttpTransportFactory with proxyUrl baked in.
    if (transport instanceof BulkTransportFactory) {
      const inner = transport;
      transport = {
        query: function (url, payload, headers) {
          return inner.query(proxyUrl + url, payload, headers);
        },
      };
    } else {
      transport = new HttpTransportFactory({
        method: transport._method,
        proxyUrl: proxyUrl,
      });
    }
  }
  return transport;
}

export const transportSvc = { getTransport };
