'use strict';

import { fixURLProtocol } from './urlUtils.js';

/**
 * URL helpers (used with Elasticsearch 7+ and OpenSearch).
 */

/**
 *
 * Parses an ES URL of the form [http|https]://[username@password:][host][:port]/[collectionName]/_search
 * Splits up the different parts of the URL.
 *
 */
function parseUrl(url) {
  url = fixURLProtocol(url);
  const a = new URL(url);

  // Extract the raw query string manually instead of using URL.search,
  // which percent-encodes characters like spaces. Strip any fragment.
  const qIndex = url.indexOf('?');
  const hashIndex = url.indexOf('#', qIndex === -1 ? 0 : qIndex);
  const queryEnd = hashIndex !== -1 ? hashIndex : url.length;
  const rawQuery = qIndex !== -1 ? url.substring(qIndex + 1, queryEnd) : '';

  const esUri = {
    protocol: a.protocol.replace(':', ''),
    host: a.host,
    pathname: a.pathname,
    username: a.username,
    password: a.password,
    query: rawQuery,
  };

  if (esUri.pathname.endsWith('/')) {
    esUri.pathname = esUri.pathname.substring(0, esUri.pathname.length - 1);
  }

  return esUri;
}

/**
 *
 * Builds ES URL of the form [protocol]://[host][:port]/[index]/[type]/[_explain|_doc]/[id]
 * for an ES document.
 *
 */
function buildDocUrl(uri, doc, addExplain) {
  const index = doc._index;
  const type = doc._type;
  const id = doc._id;

  let url = esUrlSvc.buildBaseUrl(uri);

  url = url + '/' + index + '/';
  if (!addExplain && type) {
    url = url + type + '/';
  }

  if (addExplain) {
    url = url + '_explain';
  } else if (type !== '_doc') {
    url = url + '_doc';
  }

  if (!url.endsWith('/')) {
    url += '/';
  }
  url = url + id.replace(/#/g, '%23');

  if (!addExplain) {
    url = url + '?pretty=true';
  }
  return url;
}

/**
 * Builds an _explain URL for a document.
 */
function buildExplainUrl(uri, doc) {
  return buildDocUrl(uri, doc, true);
}

/**
 *
 * Builds ES URL of the form [protocol]://[host][:port]/_render/template
 * for seeing a rendered template.
 *
 */
function buildRenderTemplateUrl(uri) {
  let url = esUrlSvc.buildBaseUrl(uri);

  url = url + '/_render/template';

  return url;
}

/**
 *
 * Builds ES URL for a search query.
 * Adds any query params if present: /_search?from=10&size=10
 */
function buildUrl(uri) {
  let url = esUrlSvc.buildBaseUrl(uri);
  url = url + uri.pathname;

  // Return original URL if no params to append.
  if (uri.params === undefined && uri.query === undefined) {
    return url;
  }

  const paramsAsStrings = [];

  if (uri.params !== undefined) {
    Object.keys(uri.params).forEach(function (key) {
      const value = uri.params[key];
      paramsAsStrings.push(key + '=' + value);
    });
  }

  if (uri.query !== undefined && uri.query !== '') {
    paramsAsStrings.push(uri.query);
  }

  // Return original URL if no params to append.
  if (paramsAsStrings.length === 0) {
    return url;
  }

  let finalUrl = url;

  if (finalUrl.substring(finalUrl.length - 1) === '?') {
    finalUrl += paramsAsStrings.join('&');
  } else {
    finalUrl += '?' + paramsAsStrings.join('&');
  }

  return finalUrl;
}

function buildBaseUrl(uri) {
  let url = uri.protocol + '://';
  url += uri.host;

  return url;
}

function setParams(uri, params) {
  uri.params = params;
}

function getHeaders(uri, customHeaders) {
  let headers = {};
  customHeaders = customHeaders || '';

  if (customHeaders.length > 0) {
    // TODO: validate JSON / shape before assignment, or throw on invalid customHeaders (today we trust the caller).
    headers = JSON.parse(customHeaders);
  } else if (
    uri.username !== undefined &&
    uri.username !== '' &&
    uri.password !== undefined &&
    uri.password !== ''
  ) {
    const authorization = 'Basic ' + btoa(uri.username + ':' + uri.password);
    headers = { Authorization: authorization };
  }

  return headers;
}

/** Removes embedded user:password@ from a URL (basic auth in the authority). */
function stripBasicAuth(url) {
  return url.replace(/(:\/\/)([^@]+)@/, '$1');
}

function isBulkCall(uri) {
  return uri.pathname.endsWith('_msearch');
}

// in the args is an id parameter like "id: 'tmdb-title-search-template'" that specifies a template
// This let's us understand when to add a /template
function isTemplateCall(args) {
  if (args && args.id) {
    return true;
  } else {
    return false;
  }
}

const esUrlSvc = {
  parseUrl: parseUrl,
  buildDocUrl: buildDocUrl,
  buildExplainUrl: buildExplainUrl,
  buildUrl: buildUrl,
  buildBaseUrl: buildBaseUrl,
  buildRenderTemplateUrl: buildRenderTemplateUrl,
  setParams: setParams,
  getHeaders: getHeaders,
  stripBasicAuth: stripBasicAuth,
  isBulkCall: isBulkCall,
  isTemplateCall: isTemplateCall,
};

export { esUrlSvc };
