'use strict';

import { queryTemplateSvc } from './queryTemplateSvc.js';
import { defaultVectaraConfig } from '../values/defaultVectaraConfig.js';

const replaceQuery = function (qOption, args, queryText) {
  return queryTemplateSvc.hydrate(args, queryText, {
    qOption: qOption,
    encodeURI: false,
    defaultKw: '\\"\\"',
  });
};

const preparePostRequest = function (searcher) {
  const pagerArgs = searcher.args.pager ? structuredClone(searcher.args.pager) : {};

  searcher.pagerArgs = Object.assign({}, pagerArgs);
  delete searcher.args.pager;

  const queryDsl = replaceQuery(searcher.config.qOption, searcher.args, searcher.queryText);

  searcher.queryDsl = queryDsl;
};

function prepare(searcher) {
  if (searcher.config === undefined) {
    searcher.config = defaultVectaraConfig;
  } else {
    // make sure config params that weren't passed through are set from
    // the default config object.
    searcher.config = Object.assign({}, defaultVectaraConfig, searcher.config);
  }

  preparePostRequest(searcher);
}

export const vectaraSearcherPreprocessorSvc = { prepare };
