'use strict';

// Executes a generic search and returns
// a set of generic documents

import SolrSearcherFactory from '../factories/solrSearcherFactory.js';
import EsSearcherFactory from '../factories/esSearcherFactory.js';
import VectaraSearcherFactory from '../factories/vectaraSearcherFactory.js';
import AlgoliaSearcherFactory from '../factories/algoliaSearchFactory.js';
import SearchApiSearcherFactory from '../factories/searchApiSearcherFactory.js';
import { activeQueries } from '../values/activeQueries.js';
import { defaultSolrConfig } from '../values/defaultSolrConfig.js';

// PRE and POST strings, can't just use HTML
// because Solr doesn't appear to support escaping
// XML/HTML tags in the content. So we do this stupid thing
const HIGHLIGHTING_PRE = 'aouaoeuCRAZY_STRING!8_______';
const HIGHLIGHTING_POST = '62362iueaiCRAZY_POST_STRING!_______';

function configFromDefault() {
  return structuredClone(defaultSolrConfig);
}

function createSearcher(fieldSpec, url, args, queryText, config, searchEngine) {
  if (searchEngine === undefined) {
    searchEngine = 'solr';
  }

  const options = {
    fieldList: fieldSpec.fieldList(),
    hlFieldList: fieldSpec.highlightFieldList(),
    url: url,
    args: args,
    queryText: queryText,
    config: config,
    type: searchEngine,
  };

  if (
    options.config &&
    options.config.basicAuthCredential &&
    options.config.basicAuthCredential.length > 0
  ) {
    // set up basic auth as a header
    const encoded = btoa(options.config.basicAuthCredential);
    if (options.config.customHeaders && options.config.customHeaders.length > 0) {
      // already something there, append a new entry
      const head = JSON.parse(options.config.customHeaders);
      head['Authorization'] = 'Basic ' + encoded;
      options.config.customHeaders = JSON.stringify(head);
    } else {
      // empty, so insert
      const head = { Authorization: 'Basic ' + encoded };
      options.config.customHeaders = JSON.stringify(head);
    }
  }

  let searcher;

  if (searchEngine === 'solr') {
    options.HIGHLIGHTING_PRE = HIGHLIGHTING_PRE;
    options.HIGHLIGHTING_POST = HIGHLIGHTING_POST;

    searcher = new SolrSearcherFactory(options);
  } else if (searchEngine === 'es') {
    searcher = new EsSearcherFactory(options);
  } else if (searchEngine === 'os') {
    searcher = new EsSearcherFactory(options);
  } else if (searchEngine === 'vectara') {
    searcher = new VectaraSearcherFactory(options);
  } else if (searchEngine === 'algolia') {
    searcher = new AlgoliaSearcherFactory(options);
  } else if (searchEngine === 'searchapi') {
    searcher = new SearchApiSearcherFactory(options);
  }

  return searcher;
}

function getActiveQueries() {
  return activeQueries.count;
}

export const searchSvc = {
  HIGHLIGHTING_PRE,
  HIGHLIGHTING_POST,
  configFromDefault,
  createSearcher,
  activeQueries: getActiveQueries,
};
export { createSearcher };
