'use strict';

import { normalDocsSvc } from './normalDocsSvc.js';

function docsWithExplainOther(docs, fieldSpec) {
  const parsedDocs = [];

  docs.forEach(function (doc) {
    const normalDoc = normalDocsSvc.createNormalDoc(fieldSpec, doc);
    parsedDocs.push(normalDoc);
  });

  return parsedDocs;
}

export const esExplainExtractorSvc = { docsWithExplainOther };
