'use strict';

import TransportFactory from './transportFactory.js';

const BulkTransportFactory = function (options) {
  TransportFactory.call(this, options);
  this.batchSender = null;
};

BulkTransportFactory.prototype = Object.create(TransportFactory.prototype);
BulkTransportFactory.prototype.constructor = BulkTransportFactory;

BulkTransportFactory.prototype.query = function query(url, payload, headers) {
  const self = this;
  if (!self.batchSender) {
    self.batchSender = new BatchSender(url, headers);
  } else if (self.batchSender.url() !== url) {
    self.batchSender.dispose();
    self.batchSender = new BatchSender(url, headers);
  }
  return self.batchSender.enqueue(payload);
};

const BatchSender = function (url, headers) {
  /* Use Elasticsearch's _msearch API to send
   * batches of searches one batch at a time
   * */

  const requestHeaders = Object.assign({ 'Content-Type': 'application/x-ndjson' }, headers);
  const self = this;
  self.enqueue = enqueue;
  self.url = getUrl;
  let queue = [];
  let pendingHttp = null;

  function finishBatch(batchSize) {
    pendingHttp = null;
    queue = queue.slice(batchSize);
  }

  function multiSearchSuccess(httpResp) {
    // Examine the responses and dequeue the corresponding
    // searches
    const bulkHttpResp = httpResp.data;
    if (bulkHttpResp.hasOwnProperty('responses')) {
      const respLen = bulkHttpResp.responses.length;
      dequeuePendingSearches(bulkHttpResp);
      finishBatch(respLen);
    } else {
      multiSearchFailed(bulkHttpResp);
    }
  }

  function multiSearchFailed(bulkHttpResp) {
    // Handle HTTP failure, which should fail all in flight searches
    let numInFlight = 0;
    queue.forEach(function (pendingQuery) {
      if (pendingQuery.inFlight) {
        pendingQuery.reject(bulkHttpResp);
        numInFlight++;
      }
    });
    finishBatch(numInFlight);
  }

  function buildMultiSearch() {
    // Batch queued searches into one message using MultiSearch API
    const sharedHeader = JSON.stringify({});
    const queryLines = [];
    queue.forEach(function (pendingQuery) {
      queryLines.push(sharedHeader);
      pendingQuery.inFlight = true;
      queryLines.push(JSON.stringify(pendingQuery.payload));
    });
    const data = queryLines.join('\n') + '\n';
    return data;
  }

  function dequeuePendingSearches(bulkHttpResp) {
    // Examine the responses and dequeue the corresponding
    // searches
    let queueIdx = 0;
    bulkHttpResp.responses.forEach(function (resp) {
      const currRequest = queue[queueIdx];
      if (resp.hasOwnProperty('error')) {
        currRequest.reject(resp);
        // individual query failure
      } else {
        // make the response look like standard response
        currRequest.resolve({ data: resp });
      }

      queueIdx++;
    });
  }

  function sendMultiSearch() {
    if (!pendingHttp && queue.length > 0) {
      // Implementation of Elasticsearch's _msearch ("Multi Search") API
      const payload = buildMultiSearch();
      const body =
        typeof payload === 'object' && payload !== null ? JSON.stringify(payload) : payload;
      pendingHttp = fetch(url, { method: 'POST', headers: requestHeaders, body: body }).then(
        function (resp) {
          const status = resp.status;
          return resp.json().then(
            function (data) {
              if (!resp.ok) {
                return Promise.reject({
                  data: data,
                  status: status,
                  statusText: resp.statusText,
                });
              }
              return { data: data, status: status };
            },
            function () {
              return Promise.reject({
                data: null,
                status: status,
                statusText: resp.statusText || 'JSON parse error',
              });
            }
          );
        }
      );
      pendingHttp.then(multiSearchSuccess, multiSearchFailed).catch(function () {
        console.debug('Failed to do multi search');
      });
    }
  }

  function enqueue(query) {
    return new Promise(function (resolve, reject) {
      const pendingQuery = {
        resolve: resolve,
        reject: reject,
        inFlight: false,
        payload: query,
      };
      queue.push(pendingQuery);
      if (timerId === null) {
        timerId = setTimeout(timerTick, 100);
      }
    });
  }

  let timerId = null;

  function timerTick() {
    sendMultiSearch();
    if (queue.length > 0) {
      timerId = setTimeout(timerTick, 100);
    } else {
      timerId = null;
    }
  }

  function getUrl() {
    return url;
  }

  self.dispose = function () {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
  };

  timerId = setTimeout(timerTick, 100);
};

export default BulkTransportFactory;
