'use strict';

import TransportFactory from './transportFactory.js';

const HttpJsonpTransportFactory = function (options) {
  TransportFactory.call(this, options);
};

HttpJsonpTransportFactory.prototype = Object.create(TransportFactory.prototype);
HttpJsonpTransportFactory.prototype.constructor = HttpJsonpTransportFactory;

let jsonpCounter = 0;

HttpJsonpTransportFactory.prototype.query = function query(url, payload, headers) {
  // JSONP doesn't support headers, so we need to encode the user password in the URL.
  // Special characters need to be encoded.
  if (headers && headers['Authorization']) {
    let userPassword = headers['Authorization'];
    userPassword = userPassword.replace('Basic ', '');
    userPassword = atob(userPassword);
    userPassword = userPassword.split(':');
    userPassword = userPassword[0] + ':' + encodeURIComponent(userPassword[1]);

    url = url.replace('://', '://' + userPassword + '@');
  }

  if (typeof document !== 'undefined') {
    // Browser environment: use script injection for JSONP
    return new Promise(function (resolve, reject) {
      const callbackName = '_splainerJsonpCallback_' + jsonpCounter++;
      const separator = url.indexOf('?') === -1 ? '?' : '&';
      const scriptUrl = url + separator + 'json.wrf=' + callbackName;

      window[callbackName] = function (data) {
        delete window[callbackName];
        if (script.parentNode) {
          script.parentNode.removeChild(script);
        }
        resolve({ data: data, status: 200 });
      };

      const script = document.createElement('script');
      script.src = scriptUrl;
      script.onerror = function () {
        delete window[callbackName];
        if (script.parentNode) {
          script.parentNode.removeChild(script);
        }
        reject({ data: null, status: 0, statusText: 'JSONP request failed' });
      };
      document.body.appendChild(script);
    });
  } else {
    // Node environment: fall back to GET fetch
    return fetch(url)
      .then(function (resp) {
        const status = resp.status;
        return resp.json().then(
          function (data) {
            if (!resp.ok) {
              return Promise.reject({ data: data, status: status, statusText: resp.statusText });
            }
            return { data: data, status: status };
          },
          function () {
            // Response body was not valid JSON
            return Promise.reject({ data: null, status: status, statusText: resp.statusText });
          }
        );
      })
      .catch(function (err) {
        if (err && err.status !== undefined) {
          return Promise.reject(err);
        }
        return Promise.reject({
          data: null,
          status: 0,
          statusText: err.message || 'Network Error',
        });
      });
  }
};

export default HttpJsonpTransportFactory;
