'use strict';

import TransportFactory from './transportFactory.js';

const HttpTransportFactory = function (options) {
  const method = options.method || 'POST';
  const proxyUrl = options.proxyUrl;

  // Strip internal keys so .options() returns only user-provided options
  const userOpts = Object.assign({}, options);
  delete userOpts.method;
  delete userOpts.proxyUrl;

  TransportFactory.call(this, userOpts);
  this._method = method;
  this._proxyUrl = proxyUrl;
};

HttpTransportFactory.prototype = Object.create(TransportFactory.prototype);
HttpTransportFactory.prototype.constructor = HttpTransportFactory;

HttpTransportFactory.prototype.query = function query(url, payload, headers) {
  if (this._proxyUrl) {
    url = this._proxyUrl + url;
  }

  const fetchOptions = { method: this._method, headers: headers };

  if (this._method === 'POST') {
    fetchOptions.body =
      typeof payload === 'object' && payload !== null ? JSON.stringify(payload) : payload;
    const mergedHeaders = Object.assign({}, headers);
    if (typeof payload === 'object' && payload !== null) {
      mergedHeaders['Content-Type'] = mergedHeaders['Content-Type'] || 'application/json';
    }
    fetchOptions.headers = mergedHeaders;
  }

  return fetch(url, fetchOptions)
    .then(function (resp) {
      const status = resp.status;
      return resp.json().then(
        function (data) {
          if (!resp.ok) {
            return Promise.reject({ data: data, status: status, statusText: resp.statusText });
          }
          return { data: data, status: status };
        },
        function () {
          // Response body was not valid JSON
          return Promise.reject({ data: null, status: status, statusText: resp.statusText });
        }
      );
    })
    .catch(function (err) {
      if (err && err.status !== undefined) {
        return Promise.reject(err);
      }
      return Promise.reject({ data: null, status: 0, statusText: err.message || 'Network Error' });
    });
};

export default HttpTransportFactory;
