'use strict';

/**
 * Tracks how many searches are currently in flight across all searcher factories.
 * Internal count is module-private; use `increment` / `decrement` / `reset` instead of assigning `count`.
 * Reading `activeQueries.count` is supported for diagnostics and tests.
 */
let count = 0;

function increment() {
  count++;
}

function decrement() {
  count--;
}

function reset() {
  count = 0;
}

export const activeQueries = Object.freeze({
  get count() {
    return count;
  },
  increment,
  decrement,
  reset,
});
